VALUES
  ('disabled-23e15ae5-moex-00210', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「媒體若未善盡查證之責，符合新聞專業倫理，那麼報導不過是□□□□， 混淆視聽，有失公正客觀。」依據此段文意，□□□□填入何者最恰當？', '["有案可稽", "捕風捉影", "言不由衷", "事出有因"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00211', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '下列「」中的成語，使用正確的選項為：', '["大家日夜苦練，爭取冠軍的企圖心早已「不言而喻」", "今年的象棋競賽，棋士們無不卯足全力「紙上談兵」", "這家餐廳的餐點價格廉、口味佳，可說「米珠薪桂」", "這次西洋劍比賽他果真勇奪金牌，真是「不孚眾望」"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00212', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '下列「」中的成語，使用正確的選項是：', '["他為人正直，重情重義，不太可能做那種「得魚忘筌」的事", "從古到今，能夠殺身成仁、捨生取義的人，可說是「鳳毛麟角」了", "林祕書能力超強，花點時間指點工讀生做事方法，不過是「犬馬之勞」", "與嫌犯對峙多時，警方以「暴虎馮河」的精神堅持到底，最後完成任務"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00213', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '下列各機關宣傳標語，何者最為恰當？', '["教育部／推廣成人教育終身學習：及時當勉勵，歲月不待人", "消防局／呼籲家戶留意用火安全：留得青山在，不怕沒柴燒", "健康保險署／建構線上病歷表供查詢：海內存知己，天涯若比鄰", "衛生福利部／防範老人失智症需趁早：欲窮千里目，更上一層樓"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00214', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '下列新聞標題，沒有出現贅字、用詞失當的選項是：', '["入冬爆院內感染，預言果然可能即將成真", "全球新冠肺炎確診病例數，累計破九千萬", "英國疫情嚴峻，政府唯恐或許將考慮實施宵禁", "全球疫情增溫，市長不捨忍痛停辦今年馬拉松大賽"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00215', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「一個音樂家究竟能與奧運產生多深的連結？『臺灣音聲100年網站』可 以找到江文也參加 1936 年在德國舉辦的奧運比賽作品，原來當時奧運還 有藝文競技項目。出生於臺灣、旅居日本的江文也，以臺灣為靈感寫下的 鋼琴曲〈城內之夜〉，改編為管弦樂〈臺灣舞曲〉，獲得奧運特別獎。該 樂曲充滿對臺灣的思念，透過『臺灣音聲100年網站』，可以聽到1937年 井上園子演出的鋼琴獨奏版本。」下列選項，最符合文意的是：', '["江文也是旅居德國的臺灣人", "一個音樂家是不應該在奧運得獎的", "江文也奧運得獎作品是以思念臺灣為主題", "1936年奧運，井上園子演奏〈臺灣舞曲〉"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00216', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「雪子陷入長考，最後假作若無其事地回信，詢問小早到新環境生活後是 否結交到新的朋友了。再收到明信片，小早只寫來一句：『揀盡寒枝不肯 棲。』」下列選項，何者最符合小早回覆之意？', '["新環境的氣候寒冷，還在適應中", "我連住處都尚未安頓好，如何想得到交朋友的事", "新認識的人都不願意理會自己，所以還沒交到朋友", "在我心中，只有你是我認定的朋友，其他人都比不上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00217', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「以我來說，在Email可以勝任的範圍內，我喜歡Email勝過電話，因為：', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00218', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '我可以自己決定什麼時候讀和回覆。2.如果沒有 Email 可以查，我會忘 記八成以上的工作資訊。3.有些人覺得用電話講比較清楚，其實是因為他 們沒能力光靠自己就把東西表達清楚，跟這種人講電話很痛苦。當然，上 面這種人寫的Email也不會讓你太好受，不過至少你可以自己控制跳躍閱 讀。」根據上文，下列敘述何者錯誤？', '["作者認為工作資訊若能以Email通知，記憶度將會較電話來得高", "作者認為Email雖有助於記憶，但電話不至於讓接受者閱讀跳躍", "作者偏好用Email，因Email有助記憶資訊且回覆時間不受限制", "作者最後一句，其實是在嘲諷溝通不良或表達不清的聯絡者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00219', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「在戰壕裡，戰士倘若開槍射擊，就容易使敵人瞄準他的位置，但是一槍 不放的戰士又如何立功？多做多錯，少做少錯，不做不錯，這話的確是經 驗之談，但是發明這句話的人可曾想過：不做不錯的『不錯』，到底有什 麼價值？」下列選項，何者最符合文意？', '["他山之石可以攻錯", "人非聖賢，孰能無過", "犯錯無妨，重要的是面對錯誤", "人生最大的錯誤是擔心犯錯而不作為"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL)
